import { Task } from '@wasp/entities';

export const getTasks = async (args, context) => {
  const { Task } = context.entities;
  return await Task.findMany({
    orderBy: {
      position: 'asc',
    },
  });
};

export const createTask = async ({ description }, context) => {
  const { Task } = context.entities;

  // Find the maximum position to determine the next position
  const maxPositionTask = await Task.findFirst({
    orderBy: {
      position: 'desc',
    },
  });

  const nextPosition = maxPositionTask ? maxPositionTask.position + 1 : 0;

  return await Task.create({
    data: {
      description,
      position: nextPosition,
    },
  });
};

export const moveTaskUp = async ({ id }, context) => {
  const { Task } = context.entities;

  // Find the current task
  const currentTask = await Task.findUnique({
    where: { id },
  });

  if (!currentTask) {
    throw new Error('Task not found');
  }

  // Find the task above (with position - 1)
  const taskAbove = await Task.findFirst({
    where: {
      position: currentTask.position - 1,
    },
  });

  if (!taskAbove) {
    throw new Error('No task above to swap with');
  }

  // Swap positions
  const [updatedCurrentTask, updatedTaskAbove] = await Promise.all([
    Task.update({
      where: { id: currentTask.id },
      data: { position: taskAbove.position },
    }),
    Task.update({
      where: { id: taskAbove.id },
      data: { position: currentTask.position },
    }),
  ]);

  return updatedCurrentTask;
};

