import { useState } from 'react';
import { useQuery, useAction } from '@wasp/queries';
import { getTasks } from '@wasp/queries';
import { createTask, moveTaskUp } from '@wasp/actions';
import './Main.css';

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskFn = useAction(createTask);
  const moveTaskUpFn = useAction(moveTaskUp, {
    optimisticUpdates: [
      {
        getQuerySpecifier: () => [getTasks],
        updateQuery: (oldData, { id }) => {
          if (!oldData) return oldData;

          const tasks = [...oldData];
          const currentIndex = tasks.findIndex(task => task.id === id);

          if (currentIndex <= 0) return tasks;

          // Swap tasks
          [tasks[currentIndex], tasks[currentIndex - 1]] = [tasks[currentIndex - 1], tasks[currentIndex]];

          return tasks;
        },
      },
    ],
  });

  const [newTaskDescription, setNewTaskDescription] = useState('');

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskDescription.trim()) return;

    try {
      await createTaskFn({ description: newTaskDescription });
      setNewTaskDescription('');
    } catch (err) {
      console.error('Failed to create task:', err);
    }
  };

  const handleMoveTaskUp = async (id: number) => {
    try {
      await moveTaskUpFn({ id });
    } catch (err) {
      console.error('Failed to move task up:', err);
    }
  };

  if (isLoading) {
    return <div className="container">Loading...</div>;
  }

  if (error) {
    return <div className="container">Error: {error.message}</div>;
  }

  return (
    <main className="container">
      <h1 className="title">Task Reordering with Optimistic Updates</h1>

      <form onSubmit={handleCreateTask} className="task-form">
        <input
          type="text"
          value={newTaskDescription}
          onChange={(e) => setNewTaskDescription(e.target.value)}
          placeholder="Enter task description"
          className="task-input"
        />
        <button type="submit" className="button button-filled">
          Add Task
        </button>
      </form>

      <div className="task-list">
        {tasks && tasks.length > 0 ? (
          tasks.map((task, index) => (
            <div key={task.id} className="task-item">
              <span className="task-description">{task.description}</span>
              {index > 0 && (
                <button
                  onClick={() => handleMoveTaskUp(task.id)}
                  className="button button-outlined move-up-button"
                >
                  Move Up
                </button>
              )}
            </div>
          ))
        ) : (
          <p className="no-tasks">No tasks yet. Add one above!</p>
        )}
      </div>
    </main>
  );
}

